func (s *transactionServer) CreateTransaction(ctx context.Context, req *pb.CreateTransactionRequest) (*pb.CreateTransactionResponse, error) {
	if req.GetAccountId() == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}
	if req.GetTransactionId() == "" {
		return nil, status.Error(codes.InvalidArgument, "transaction_id is required")
	}
	if req.GetCurrency() == "" {
		return nil, status.Error(codes.InvalidArgument, "currency is required")
	}
	if req.GetAmount() == 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be non-zero")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	currentCurrency, ok := s.currency[req.GetAccountId()]
	if ok && currentCurrency != req.GetCurrency() {
		return nil, status.Error(codes.FailedPrecondition, "currency mismatch for account")
	}
	if !ok {
		s.currency[req.GetAccountId()] = req.GetCurrency()
	}

	s.balances[req.GetAccountId()] += req.GetAmount()

	return &pb.CreateTransactionResponse{
		TransactionId: req.GetTransactionId(),
		Status:        "SUCCESS",
		Balance:       s.balances[req.GetAccountId()],
	}, nil
}

func (s *transactionServer) GetBalance(ctx context.Context, req *pb.GetBalanceRequest) (*pb.GetBalanceResponse, error) {
	if req.GetAccountId() == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	currency := s.currency[req.GetAccountId()]
	return &pb.GetBalanceResponse{
		AccountId: req.GetAccountId(),
		Balance:   s.balances[req.GetAccountId()],
		Currency:  currency,
	}, nil
}

